import React from 'react';
import { Link } from 'react-router-dom';
import styles from './SplitBanner.module.css';

/**
 * Banner — 메인 배너 컴포넌트
 *
 * Props:
 *   year       {string}  — "2026"
 *   title      {string}  — "Spring Summer Womenswear Collection"
 *   theme      {string}  — "light" | "dark"
 *   img        {string}  — import한 이미지 경로 (없으면 placeholder 배경색)
 *   bg         {string}  — 이미지 없을 때 배경색
 *   viewLink   {string}  — href
 *   viewStyle  {string}  — "box" | "underline"
 */
function SplitBanner({
  year = '2026',
  title,
  theme = 'light',
  img,
  bg = '#c8c5bc',
  viewLink = '#!',
  viewStyle = 'box',
}) {
  const isDark = theme === 'dark';

  return (
    <section
      className={`${styles.banner} ${isDark ? styles.dark : styles.light}`}
      style={{ background: bg }}
    >
      {/* Background image */}
      {img && (
        <img src={img} alt="" className={styles.bgImg} />
      )}

      {/* Center overlay */}
      <div className={styles.overlay}>
        <p className={styles.year}>{year}</p>
        <p className={styles.title}>{title}</p>

        {viewStyle === 'box' ? (
          <Link to={viewLink} className={`${styles.viewBtn} ${styles.viewBtnBox} ${isDark ? styles.viewBtnDark : ''}`}>
            VIEW
          </Link>
        ) : (
          <Link to={viewLink} className={`${styles.viewBtn} ${styles.viewBtnLine} ${isDark ? styles.viewBtnDark : ''}`}>
            VIEW <span className={styles.btnUnderline} />
          </Link>
        )}
      </div>

      {/* Scroll indicator */}
      <div className={styles.scrollIndicator}>
        <span className={`${styles.scrollText} ${isDark ? styles.scrollDark : ''}`}>SCROLL</span>
        <div className={`${styles.scrollLine} ${isDark ? styles.scrollLineDark : ''}`} />
      </div>
    </section>
  );
}

export default SplitBanner;
